1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause?: string; damages: Damage[] };
4	type QuoteStep = { op?: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Step[] };
8	
9	const PROCESSING_FEE = 5;
10	const COMPONENT_BASE_PER_ITEM = 25;
11	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	
23	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	};
29	
30	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
31	  sword: 1000,
32	};
33	
34	type PolicyState = { items: Item[]; remainingCap: number };
35	
36	export function runScenario(input: unknown): unknown {
37	  const { customer, steps } = input as Scenario;
38	  const years = customer?.yearsWithMHPCO ?? 0;
39	  const policies: Record<number, PolicyState> = {};
40	  const results = steps.map((step, index) => {
41	    if (step.op === "claim") return computeClaim(step, policies);
42	    const isFollowUp = index >= 1;
43	    const insuranceSum = step.items.reduce((s, i) => s + INSURANCE_VALUE_BY_TYPE[i.type], 0);
44	    policies[index] = { items: step.items, remainingCap: 2 * insuranceSum };
45	    return { premium: computePremium(step.items, years, isFollowUp) };
46	  });
47	  return { results };
48	}
49	
50	function computeClaim(step: ClaimStep, policies: Record<number, PolicyState>): { payout: number; remainingCap: number } {
51	  const policy = policies[step.policy];
52	  let payout = 0;
53	  for (const damage of step.incident.damages) {
54	    payout += Math.max(0, damage.amount - CLAIM_DEDUCTIBLE);
55	  }
56	  policy.remainingCap -= payout;
57	  return { payout, remainingCap: policy.remainingCap };
58	}
59	
60	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
61	  if (items.length === 0) return PROCESSING_FEE;
62	  if (items.every(isComponent)) return componentsPremium(items);
63	  return mainItemsPremium(items, years, isFollowUp);
64	}
65	
66	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
67	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
68	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
69	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
70	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
71	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
72	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
73	}
74	
75	function itemSubtotal(item: Item): number {
76	  const base = BASE_PREMIUM_BY_TYPE[item.type];
77	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
78	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
79	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
80	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
81	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
82	}
83	
84	function isHighlyEnchanted(item: Item): boolean {
85	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
86	}
87	
88	function componentsPremium(items: Item[]): number {
89	  const runes = items.filter((i) => i.type === "rune").length;
90	  const moonstones = items.filter((i) => i.type === "moonstone").length;
91	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
92	}
93	
94	function componentTypeBase(count: number): number {
95	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
96	}
97	
98	function isComponent(item: Item): boolean {
99	  return item.type === "rune" || item.type === "moonstone";
100	}
101	
102	function premiumFromBase(base: number): number {
103	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
104	}
